const fs = require('fs');
const path = '/tmp/lead_queue.json';
let q = { cycles: 0, leads: [] };
try { q = JSON.parse(fs.readFileSync(path, 'utf8')); } catch(e) {}

// Find processing leads
const processing = q.leads.filter(l => l.status === 'processing');

if (processing.length === 0) {
  return { ready: false, message: 'No leads to DM' };
}

const lead = processing[0];

// DM templates (rotate by cycle)
const templates = [
  { subject: 'Quick question for {first}', body: 'Hi {first},\n\nI work with {industry} business owners who are stretched thin.\n\nQuick question: What\'s the ONE task you\'d delegate right now?\n\nReply directly. Curious what your biggest time-drain is.\n\nBest,\nAyan' },
  { subject: '{first}, curious about something', body: 'Hi {first},\n\nQuick one — I\'m talking to a few {industry} owners and everyone has a different answer:\n\nWhat\'s the most time-consuming admin task in your business right now?\n\nJust curious — reply if you have a sec.\n\nBest,\nAyan' },
  { subject: '{first}, 2 min question', body: 'Hi {first},\n\nIf you could free up 15 hours/week in your {industry} business, what would you do?\n\nI help business owners do exactly this. Reply if curious.\n\nBest,\nAyan' }
];

const tpl = templates[(q.cycles || 0) % templates.length];
const first = (lead.business_name || '').split(' ')[0] || lead.business_name;

const subject = tpl.subject.replace('{first}', first);
const body = tpl.body.replace('{first}', first).replace(/{industry}/g, lead.industry || 'your industry');

return {
  ready: true,
  lead,
  first_name: first,
  subject,
  body,
  to_email: lead.email,
  business: lead.business_name,
  industry: lead.industry || 'general'
};

const fs = require('fs');
const path = '/tmp/lead_queue.json';
const dmPath = '/tmp/lead_dms.json';

let q = { cycles: 0, leads: [] };
try { q = JSON.parse(fs.readFileSync(path, 'utf8')); } catch(e) {}

const business = $json.business || '';
const email = $json.to_email || '';
const subject = $json.subject || '';
const body = $json.body || '';

// Mark lead as dm_sent
for (let i = 0; i < q.leads.length; i++) {
  if (q.leads[i].business_name === business) {
    q.leads[i].status = 'dm_sent';
    q.leads[i].dm_sent_at = new Date().toISOString();
    break;
  }
}

fs.writeFileSync(path, JSON.stringify(q, null, 2));

// Log DM to separate file
let dms = [];
try { dms = JSON.parse(fs.readFileSync(dmPath, 'utf8')); } catch(e) {}
dms.push({
  business,
  email,
  subject,
  type: 'initial',
  sent_at: new Date().toISOString()
});
if (dms.length > 500) dms = dms.slice(-500);
fs.writeFileSync(dmPath, JSON.stringify(dms, null, 2));

// Save client brief
const brief = `# ${business}\n\n**Industry:** ${$json.industry}\n**Email:** ${email}\n\n---\n\n## 📬 DM Sent\n\n**Subject:** ${subject}\n**Body:** ${body}\n\n---\n\n## 📋 Status\n- [x] DM sent — waiting for reply\n- [ ] Client replied — check Gmail inbox\n- [ ] Meeting scheduled\n- [ ] Payment received\n- [ ] Work started`;

const briefPath = '/tmp/briefs/' + business.replace(/[^a-zA-Z0-9]/g, '_') + '.md';
try { fs.mkdirSync('/tmp/briefs', {recursive: true}); } catch(e) {}
try { fs.writeFileSync(briefPath, brief); } catch(e) {}

return {
  status: 'dm_sent',
  business,
  email,
  subject,
  brief_saved: true
};
